class Animal:
    def speak(self): print('Sound')

class Dog(Animal):
    def speak(self): print('Woof!')  # Override

d = Dog()
d.speak()  # Woof!

examples.code:
class Person:
    def __init__(self, name):
        self.name = name

class Employee(Person):
    def __init__(self, name, emp_id):
        super().__init__(name)  # Call parent constructor
        self.emp_id = emp_id

e = Employee('Alice', 101)
print(e.name, e.emp_id)  # Alice 101
